mapper.select:
select

from chat_group cg
inner join chat_group_user cgu on cg.id = cgu.chat_group_id and cg.org_id = cgu.org_id and cgu.deleted = 0
where cg.deleted = 0 and cg.status = 1 and cg.org_id = #{ew.orgId}

    and cg.group_name like concat('%', #{ew.groupName}, '%')

and cgu.user_id = #{ew.userId}
